     2→import { getAllBooks, getFeaturedBooks } from "../../src/lib/markdown";
     3→
     4→describe("Integration: Books", () => {
     5→  test("getAllBooks returns an array", () => {
     6→    const books = getAllBooks();
     7→    expect(Array.isArray(books)).toBe(true);
     8→  });
     9→
    10→  test("getAllBooks entries have required fields", () => {
    11→    const books = getAllBooks();
    12→    books.forEach((book) => {
    13→      expect(typeof book.slug).toBe("string");
    14→      expect(book.slug.length).toBeGreaterThan(0);
    15→      expect(typeof book.title).toBe("string");
    16→      expect(book.title.length).toBeGreaterThan(0);
    17→      expect(typeof book.date).toBe("string");
    18→      expect(Array.isArray(book.authors)).toBe(true);
    19→      expect(Array.isArray(book.chapters)).toBe(true);
    20→      expect(typeof book.featured).toBe("boolean");
    21→      expect(typeof book.draft).toBe("boolean");
    22→    });
    23→  });
    24→
    25→  test("getAllBooks is sorted newest first", () => {
    26→    const books = getAllBooks();
    27→    for (let i = 1; i < books.length; i++) {
    28→      expect(books[i - 1].date >= books[i].date).toBe(true);
    29→    }
    30→  });
    31→
    32→  test("getFeaturedBooks returns only books with featured: true", () => {
    33→    const featured = getFeaturedBooks();
    34→    featured.forEach((book) => {
    35→      expect(book.featured).toBe(true);
